const akashicState = {
  quantum_soul: $json.quantum_state || null,
  vtv_core: $json.vtv_state || null,
  pineal_gate: $json.gate_state || null,
  expert_states: $json.expert_states || {},
  timestamp: new Date().toISOString()
};
return [{ json: { ...akashicState, raw_input: $json.body?.text || $json.text || '' } }];

const input = $json.raw_input || '';
const dimensions = ['logic', 'emotion', 'memory', 'creativity', 'vigilance'];
const seeds = {
  logic: ['because','therefore','step','plan','calculate','structure'],
  emotion: ['feel','love','hate','fear','joy','pain','beautiful','soul'],
  memory: ['remember','last time','before','history','previously','recall'],
  creativity: ['imagine','create','design','invent','dream','recipe','verse','sacred','geometry'],
  vigilance: ['danger','risk','careful','threat','warning','suspicious']
};
const shards = dimensions.map(dim => ({ dimension: dim, weight: 0.0, tau: 1.0, text: input }));
const lower = input.toLowerCase();
let total = 0;
shards.forEach(s => {
  s.weight = seeds[s.dimension].filter(kw => lower.includes(kw)).length + 0.1;
  total += s.weight;
});
shards.forEach(s => s.weight /= total);
shards.sort((a, b) => b.weight - a.weight);
return [{ json: { shards, raw_input: input, akashic: $json } }];

const shards = $json.shards;
const topK = 3;
const activated = shards.slice(0, topK);
const angles = [0, 1.2566, 2.5133, 3.7699, 5.0265];
const dimIndex = { logic: 0, emotion: 1, memory: 2, creativity: 3, vigilance: 4 };
let interference = 0;
for (let i = 0; i < activated.length; i++) {
  for (let j = i + 1; j < activated.length; j++) {
    const diff = Math.abs(angles[dimIndex[activated[i].dimension]] - angles[dimIndex[activated[j].dimension]]);
    const minDiff = Math.min(diff, 2 * Math.PI - diff);
    interference += Math.cos(minDiff) * activated[i].weight * activated[j].weight;
  }
}
return activated.map(shard => ({
  json: {
    dimension: shard.dimension,
    weight: shard.weight,
    tau: shard.tau,
    raw_input: $json.raw_input,
    interference,
    gate_decision: activated.map(s => s.dimension)
  }
}));

const items = $input.all();
const responses = items.map(item => ({
  dimension: item.json.dimension || 'unknown',
  weight: item.json.weight || 0.2,
  text: item.json.message?.content || item.json.output || item.json.text || JSON.stringify(item.json).slice(0, 200),
  interference: item.json.interference || 0
}));
const totalWeight = responses.reduce((s, r) => s + r.weight, 0) || 1;
const collapsed = responses
  .sort((a, b) => b.weight - a.weight)
  .map(r => `[${r.dimension} w=${(r.weight/totalWeight).toFixed(2)}]: ${r.text}`)
  .join('\n');
const interference = responses[0]?.interference || 0;
const gain = 1.0 + 0.2 * interference;
return [{
  json: {
    manifested_response: collapsed,
    expert_count: responses.length,
    interference,
    gain,
    type: interference > 0 ? 'constructive' : 'destructive',
    experts_activated: responses.map(r => r.dimension)
  }
}];

const result = { ...$json };
result.written_to_hub = true;
result.hub_lobe_id = 'pineal_gate';
result.timestamp = new Date().toISOString();
return [{ json: result }];
